input.command:
python -c "
from outlines.prompts import prompt, register_filter, unregister_filter

register_filter('shout', lambda s: s.upper() + '!')

@prompt
def greet(name):
    '''Hello {{ name | shout }}'''

print(greet('world'))

unregister_filter('shout')

try:
    @prompt
    def greet2(name):
        '''Hello {{ name | shout }}'''
    print(greet2('world'))
except Exception as e:
    print('Expected error after unregister:', e)
"
